from flask import Flask, send_file, jsonify, request, g
import os
from io import BytesIO

app = Flask(__name__)

INVOICES_DIR = os.path.join(os.path.dirname(__file__), 'invoices')
os.makedirs(INVOICES_DIR, exist_ok=True)

def get_invoice_path(invoice_id):
    return os.path.join(INVOICES_DIR, f'invoice_{invoice_id}.pdf')

def verify_invoice_ownership(invoice_id, user_id):
    invoice_user_mapping = {
        1: 'user1',
        2: 'user1', 
        3: 'user2',
        4: 'user3',
        5: 'user1',
    }
    
    return invoice_user_mapping.get(invoice_id) == user_id

@app.before_request
def simulate_auth_middleware():
    g.user_id = 'user1'

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    user_id = g.user_id
    
    if not verify_invoice_ownership(invoice_id, user_id):
        return jsonify({'error': 'Unauthorized access to invoice'}), 403
    
    invoice_path = get_invoice_path(invoice_id)
    
    if not os.path.exists(invoice_path):
        return jsonify({'error': 'Invoice not found'}), 404
    
    try:
        return send_file(
            invoice_path,
            mimetype='application/pdf',
            as_attachment=True,
            download_name=f'invoice_{invoice_id}.pdf'
        )
    except Exception as e:
        return jsonify({'error': 'Failed to download invoice'}), 500

